export type GanttTask = {
    id: string;
    label: string;
    startDate: string;
    endDate: string;
    progress?: number;
    color?: string;
    children?: GanttTask[];
    dependencies?: string[];
};
export type FlatTask = {
    task: GanttTask;
    depth: number;
    parentId: string | null;
    hasChildren: boolean;
    index: number;
};
export type DragState = {
    type: 'move';
    taskId: string;
    startX: number;
    originalStart: string;
    originalEnd: string;
} | {
    type: 'resize-left';
    taskId: string;
    startX: number;
    originalStart: string;
    originalEnd: string;
} | {
    type: 'resize-right';
    taskId: string;
    startX: number;
    originalStart: string;
    originalEnd: string;
} | null;
